    ...input,
    config: CONFIG,
    chat_notification: { payload: { text: chatText } },
    notification: {
      schema_version: '1.0',
      surface: CONFIG.review.google_chat_configured === true ? 'GOOGLE_CHAT' : 'NOT_CONFIGURED',
