function htmlToText(value) {
  let s = String(value == null ? '' : value);
  if (!s) return '';
  s = s
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<blockquote[\s\S]*?<\/blockquote>/gi, ' ')
    .replace(/<div[^>]*class=["'][^"']*(gmail_quote|gmail_attr)[^"']*["'][\s\S]*$/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\u00a0/g, ' ');
  return s;
}

function stripQuotedReply(value) {
  let s = String(value == null ? '' : value);
  if (!s) return '';

  s = s.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  const cutPatterns = [
    /\nOn .{0,500}wrote:\s*\n[\s\S]*$/i,
    /\n-{2,}\s*Original Message\s*-{2,}[\s\S]*$/i,
    /\nFrom:\s+.+\nSent:\s+.+\nTo:\s+.+[\s\S]*$/i
  ];

  for (const rx of cutPatterns) s = s.replace(rx, '');

  return s
    .split('\n')
    .filter(line => !/^\s*>/.test(line))
    .join('\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function cleanText(value) {
  return stripQuotedReply(String(value == null ? '' : value).trim());
}

function cleanHtml(value) {
  return cleanText(htmlToText(value));
}

function firstUseful(values, html = false) {
  for (const value of values) {
    if (value === null || value === undefined) continue;
    const raw = typeof value === 'object' ? JSON.stringify(value) : String(value);
    const cleaned = html ? cleanHtml(raw) : cleanText(raw);
    if (cleaned && cleaned !== '{}' && cleaned !== '[]') return cleaned;
  }
  return '';
}

function path(obj, keys) {
  let cur = obj;
  for (const key of keys) {
    if (cur === null || cur === undefined) return undefined;
    cur = cur[key];
  }
  return cur;
}

function collectStrings(obj, out = [], seen = new Set(), depth = 0) {
  if (obj === null || obj === undefined || depth > 7) return out;

  if (typeof obj === 'string') {
    if (obj.trim()) out.push(obj);
    return out;
  }

  if (typeof obj !== 'object') return out;
  if (seen.has(obj)) return out;
  seen.add(obj);

  const priority = [
    'reply_text', 'text', 'plain_text', 'body_text', 'email_body_text',
    'reply_html', 'html', 'body_html', 'email_body_html',
    'body', 'content', 'email_body', 'message', 'content_preview', 'preview', 'snippet'
  ];

  for (const k of priority) {
    if (Object.prototype.hasOwnProperty.call(obj, k)) collectStrings(obj[k], out, seen, depth + 1);
  }

  for (const [k, v] of Object.entries(obj)) {
    if (!priority.includes(k)) collectStrings(v, out, seen, depth + 1);
  }

  return out;
}

function emailObject(http) {
  if (!http || typeof http !== 'object') return {};
  if (http.body && typeof http.body === 'object') return http.body;
  if (http.data && typeof http.data === 'object') return http.data;
  if (http.email && typeof http.email === 'object') return http.email;
  return http;
}

function bestHydratedText(http) {
  const email = emailObject(http);
  const roots = [email, http && http.body, http && http.data, http && http.email, http].filter(Boolean);

  const textCandidates = [];
  const htmlCandidates = [];

  for (const root of roots) {
    textCandidates.push(
      path(root, ['reply_text']),
      path(root, ['text']),
      path(root, ['plain_text']),
      path(root, ['body_text']),
      path(root, ['email_body_text']),
      path(root, ['content_preview']),
      path(root, ['preview']),
      path(root, ['snippet'])
    );

    htmlCandidates.push(
      path(root, ['reply_html']),
      path(root, ['html']),
      path(root, ['body_html']),
      path(root, ['email_body_html']),
      typeof path(root, ['body']) === 'string' ? path(root, ['body']) : null,
      path(root, ['body', 'html']),
      path(root, ['email_body']),
      path(root, ['content'])
    );
  }

  const direct = firstUseful(textCandidates, false);
  if (direct) return direct;

  const html = firstUseful(htmlCandidates, true);
  if (html) return html;

  const allStrings = [];
  for (const root of roots) collectStrings(root, allStrings);
  return firstUseful(allStrings, true) || firstUseful(allStrings, false);
}

