// HMZ_SENDER_TOKEN_RESOLUTION_V2
function hmzSenderFirstNonEmpty(...values) {
  for (const value of values) {
    const s = String(value == null ? '' : value).trim();
    if (s && s !== '{}' && s !== '[]' && s.toLowerCase() !== 'null' && s.toLowerCase() !== 'undefined') return s;
  }
  return '';
}

function hmzSenderNameFromEmail(email) {
  const e = String(email || '').toLowerCase();
  if (e.startsWith('zahid@')) return 'Zahid';
  if (e.startsWith('hamzah@') || e.startsWith('hamza@')) return 'Hamza';
  return '';
}

function hmzSenderCleanResolvedDraft(text) {
  return String(text == null ? '' : text)
    .replace(/,\s*\./g, '.')
    .replace(/\s+\./g, '.')
    .replace(/\(\s*\)/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/Thanks,\s*\./gi, 'Thanks.')
    .replace(/Understood,\s*\./gi, 'Understood.')
    .replace(/Hi,\s*\./gi, 'Hi.')
    .trim();
}

function hmzSenderFindUnresolvedTokens(text) {
  const s = String(text || '');
  const matches = [];
  for (const m of s.matchAll(/<<\s*[^>]+\s*>>/g)) matches.push(m[0]);
  for (const m of s.matchAll(/\{\{\s*[^}]+\s*\}\}/g)) matches.push(m[0]);
  return [...new Set(matches)];
}

function hmzSenderResolveString(value, ctx) {
  let s = String(value == null ? '' : value);
  s = s.replace(/<<\s*([a-zA-Z0-9_]+)\s*>>/g, (m, key) => {
    if (Object.prototype.hasOwnProperty.call(ctx, key)) return ctx[key] || '';
    return m;
  });
  s = s.replace(/\{\{\s*([a-zA-Z0-9_]+)(?:\|([^}]*))?\s*\}\}/g, (m, key, fallback) => {
    if (Object.prototype.hasOwnProperty.call(ctx, key) && ctx[key]) return ctx[key];
    if (fallback !== undefined) return fallback;
    return m;
  });
  return hmzSenderCleanResolvedDraft(s);
}

function hmzResolveDraftTokensInPlace(input) {
  if (!input || typeof input !== 'object') return input;

  const caseInput = input.case_input || input.__hmz_intake_output || input;
  const senderHandoff = input.sender_handoff || caseInput.sender_handoff || {};
  const draft =
    input.draft ||
    senderHandoff.draft ||
    caseInput.draft ||
    (caseInput.decision && caseInput.decision.draft) ||
    {};

  const nes = input.nes || senderHandoff.nes || caseInput.nes || {};
  const raw = input.raw_payload || caseInput.raw_payload || {};
  const lead = nes.lead || caseInput.lead || input.lead || {};
  const senderConfig =
    draft.sender_config ||
    input.sender_config ||
    senderHandoff.sender_config ||
    caseInput.sender_config ||
    (caseInput.config && caseInput.config.sender_config) ||
    {};

  const emailAccount = hmzSenderFirstNonEmpty(
    senderConfig.email,
    senderConfig.email_account,
    senderConfig.eaccount,
    nes.email_account,
    raw.email_account,
    raw.eaccount,
    input.email_account
  );

  const senderName = hmzSenderFirstNonEmpty(
    senderConfig.senderName,
    senderConfig.sender_name,
    senderConfig.name,
    input.senderName,
    input.sender_name,
    hmzSenderNameFromEmail(emailAccount),
    'Hamza'
  );

  const firstName = hmzSenderFirstNonEmpty(
    nes.lead_first_name,
    nes.first_name,
    lead.first_name,
    lead.firstName,
    raw.firstName,
    raw.first_name,
    input.firstName,
    input.first_name
  );

  const ctx = {
    firstName,
    First_name: firstName || 'there',
    first_name: firstName,
    senderName,
    sender_name: senderName,
    sendingAccountName: senderName
  };

  for (const field of ['draft_text', 'reply_text', 'body', 'text']) {
    if (typeof draft[field] === 'string') draft[field] = hmzSenderResolveString(draft[field], ctx);
  }

  if (draft.reply && typeof draft.reply === 'object') {
    for (const field of ['text', 'body', 'draft_text']) {
      if (typeof draft.reply[field] === 'string') draft.reply[field] = hmzSenderResolveString(draft.reply[field], ctx);
    }
  }

  const finalDraftText = hmzSenderFirstNonEmpty(
    draft.draft_text,
    draft.reply_text,
    draft.text,
    draft.body,
    draft.reply && draft.reply.text,
    draft.reply && draft.reply.body
  );

  const unresolved = hmzSenderFindUnresolvedTokens(finalDraftText);
  draft.missing_variables = unresolved;

  if (input.draft) input.draft = draft;
  if (senderHandoff.draft) senderHandoff.draft = draft;
  if (caseInput.draft) caseInput.draft = draft;
  if (caseInput.decision && caseInput.decision.draft) caseInput.decision.draft = draft;

  input._hmz_sender_token_resolution = {
    applied: true,
    senderName,
    firstNamePresent: !!firstName,
    unresolved_count: unresolved.length,
    unresolved
  };

  return input;
}

function runSendGates(item) {
  const input = hmzResolveDraftTokensInPlace(item || {});
  const cfg = SENDER_CONFIG;
  const reasons = [];

  if (input.sender_validation && input.sender_validation.valid !== true) {
    reasons.push('sender_validation_failed');
  }

  const safeValidationMode =
    cfg.OPERATING_MODE === 'VALIDATION' &&
    cfg.DRY_RUN === true &&
    Array.isArray(cfg.LIVE_CAMPAIGNS) &&
    cfg.LIVE_CAMPAIGNS.length === 0;

  const supervisedLiveMode =
    cfg.OPERATING_MODE === 'SUPERVISED_VALIDATION' &&
    cfg.DRY_RUN === false &&
    Array.isArray(cfg.LIVE_CAMPAIGNS) &&
    cfg.LIVE_CAMPAIGNS.length > 0 &&
    cfg.LIVE_CREDENTIAL_READY === true;

  const configGatePassed = safeValidationMode || supervisedLiveMode;
  if (!configGatePassed) reasons.push('config_gate_failed');

  const approval = input.approval || {};
  const approvalGatePassed = approval.approved === true;
  if (!approvalGatePassed) reasons.push('approval_missing');

  const nes = input.nes || {};
  const campaignId = nes.campaign_id || null;
  const liveCampaignSendAllowed = cfg.LIVE_CAMPAIGNS.includes(campaignId);
  if (!liveCampaignSendAllowed) reasons.push('live_campaigns_empty_live_send_blocked');

  const senderGatePassed = !!nes.eaccount && nes.eaccount !== 'UNKNOWN';
  if (!senderGatePassed) reasons.push('sender_gate_failed');

  const draft = input.draft || {};
  const draftText = typeof draft.draft_text === 'string' ? draft.draft_text : null;
  const unresolvedTokens = draftText ? draftText.match(/\[\[[^\]]+\]\]|<<[^>]+>>/g) || [] : [];
  const draftVariableGatePassed = draftText === null || unresolvedTokens.length === 0;
  if (!draftVariableGatePassed) reasons.push('unresolved_template_variables');

  const decision = input.decision || {};
  const suppressionRequired =
    decision.address_suppression_intent === 'ORGANISATION_DNC' ||
    decision.address_suppression_intent === 'GLOBAL_BLOCKLIST' ||
    decision.durable_dnc_intent === true;

  const dryRunGatePassed = cfg.DRY_RUN === true;
  const dryRunFlagValid = cfg.DRY_RUN === true || cfg.DRY_RUN === false;
  if (!dryRunFlagValid) reasons.push('dry_run_flag_invalid');

  const passed =
    (input.sender_validation ? input.sender_validation.valid === true : true) &&
    configGatePassed &&
    approvalGatePassed &&
    senderGatePassed &&
    draftVariableGatePassed &&
    dryRunFlagValid;

  return {
    ...input,
    gates: {
      config_gate_passed: configGatePassed,
      approval_gate_passed: approvalGatePassed,
      live_campaign_send_allowed: liveCampaignSendAllowed,
      sender_gate_passed: senderGatePassed,
      draft_variable_gate_passed: draftVariableGatePassed,
      unresolved_tokens: unresolvedTokens,
      suppression_required: suppressionRequired,
      dry_run_gate_passed: dryRunGatePassed,
      passed,
      reasons,
    },
  };
}

return items.map(item => ({ json: runSendGates(item.json || {}) }));

