  let   senderName  = (sCfg && (sCfg.senderName || sCfg.sender_name)) || null;
  if (!senderName) {
    const _toJson = input.raw_payload &&
      input.raw_payload._instantly_hydrated_email &&
      Array.isArray(input.raw_payload._instantly_hydrated_email.to_address_json) &&
      input.raw_payload._instantly_hydrated_email.to_address_json[0];
    if (_toJson && typeof _toJson.name === 'string' && _toJson.name.trim()) {
      senderName = _toJson.name.trim().split(/\s+/)[0];
    }
  }
  if (!senderName && eKey) {
    const _lp = eKey.split('@')[0];
    if (_lp) senderName = _lp.charAt(0).toUpperCase() + _lp.slice(1);
  }
  const bookingLink = sCfg && sCfg.bookingLink ? sCfg.bookingLink : null;
  const replyText   = String((nes.reply && nes.reply.text) || '');
  const campaignCtx = nes.campaign_context || {};

  const tmpl              = MI_TEMPLATES[microIntent] || null;
  const deterministicText = tmpl ? renderTemplate(tmpl, firstName, senderName, bookingLink) : null;

  let draftText   = null;
  let draftSource = 'none';
  let aiAttempt   = null;

  const canTryAI = (
    AI_DRAFT_MODE  === 'supervised' &&
    draftPolicy    === 'AI_SUPERVISED_OR_TEMPLATE' &&
    decision.reply_permitted !== false &&
    replyText.trim().length > 0
  );

  if (canTryAI && AI_API_KEY) {
    const prompt   = buildAIPrompt(microIntent, replyText, firstName, campaignCtx) + ACTIVE_RULE_GUIDANCE;
    const aiResult = await callAI(prompt, AI_API_KEY);
    aiAttempt      = aiResult;
    if (aiResult.ok && aiResult.draft_text) {
      const errs = validateAI(aiResult.draft_text, microIntent);
      if (errs.length === 0) {
        const resolved = aiResult.draft_text
          .replace(/<<firstName>>/g,   firstName   || '')
          .replace(/<<senderName>>/g,  senderName  || '')
          .replace(/<<bookingLink>>/g, bookingLink || 'https://calendar.app.google/bNXWJkS3xz3yqdW36');
        draftText   = resolved;
        draftSource = 'ai_supervised';
        if (senderName) {
          const _esc = senderName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          const _signoffRx = new RegExp(
            '\\n+(?:(?:best|regards|thanks|kind\\s+regards|sincerely|cheers)[,.]?[\\s]*\\n*)?\\s*' + _esc + '\\s*$',
            'i'
          );
          const _stripped = draftText.trimEnd().replace(_signoffRx, '');
          draftText = _stripped.trimEnd() + '\n\n' + senderName;
        }
        const BOOKING_LINK = 'https://calendar.app.google/bNXWJkS3xz3yqdW36';
        const _ctaRx = /(\b(?:you\s+can\s+)?book(?:\s+(?:a\s+)?time)?(?:\s+here)?)\s*:\s*(?!https?:\/\/)\.?[ \t]*/gi;
        draftText = draftText.replace(_ctaRx, '$1: ' + BOOKING_LINK);
        const _bkEsc = BOOKING_LINK.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        let _bkSeen = false;
        draftText = draftText.replace(new RegExp(_bkEsc, 'g'), () => _bkSeen ? '' : (_bkSeen = true, BOOKING_LINK));
      } else {
        draftText   = deterministicText;
        draftSource = 'ai_failed_fallback';
        aiAttempt   = { ...aiResult, validation_errors: errs };
      }
    } else {
      draftText   = deterministicText;
      draftSource = 'ai_failed_fallback';
    }
  } else if (['AI_SUPERVISED_OR_TEMPLATE','FIXED_TEMPLATE','FIXED_TEMPLATE_SUPPRESS_ONLY'].includes(draftPolicy)) {
    draftText   = deterministicText;
    draftSource = 'deterministic_template';
  } else if (draftPolicy === 'AI_COMMERCIAL_SUPERVISED') {
    // SL-PHASE-4A: Non-committal context-aware commercial draft
    var _di4d = cls.detected_intents || [];
    var _hP = microIntent === 'PRICING_REQUEST' || _di4d.some(function(i){return i.micro_intent==='PRICING_REQUEST';});
    var _hD = _di4d.some(function(i){return i.micro_intent==='DATA_SECURITY_REQUEST';});
    var _hC = _di4d.some(function(i){return i.micro_intent==='CONTRACT_TERMS_REQUEST';});
    var _hPi = _di4d.some(function(i){return i.micro_intent==='SMALL_SCALE_PILOT_REQUEST';});
    var _hS = _di4d.some(function(i){return i.micro_intent==='SCOPE_REQUEST';});
    var _gr = firstName ? ('Thanks, ' + firstName + '.') : 'Thanks.';
    var _ps = [_gr, 'Happy to answer these.'];
    if (_hP)  _ps.push('Pricing depends on scope. I want to give you a number that actually reflects your situation rather than a generic figure. The best way to do that is a brief 10-minute conversation.');
    if (_hD)  _ps.push('Your data would only be used for the agreed campaign. We would not sell it, share it, or use it outside the agreed scope.');
    if (_hC)  _ps.push('Yes, there would be a simple agreement before anything starts. Nothing complex or long-term at this stage.');
    if (_hPi) _ps.push('Yes, we can test this with one small campaign first before committing to anything bigger. That is actually how we prefer to start.');
    if (_hS)  _ps.push('Happy to explain exactly what is involved. The short version: we define the target, build a focused prospect list, write and run the outreach, then review results together.');
    _ps.push('If it helps to talk through the specifics, you can grab 10 minutes here: https://calendar.app.google/bNXWJkS3xz3yqdW36');
    if (senderName) _ps.push(senderName);
    draftText   = _ps.filter(function(p){return p.trim().length>0;}).join('\n\n');
    draftSource = 'ai_commercial_supervised';
  } else {
    draftText   = null;
    draftSource = draftPolicy === 'NO_DRAFT' ? 'none' : 'human_only';
  }

  // Token safety check: reject any unresolved <<...>> or {{...}} in final draft_text
  if (draftText && (/<<\w+>>/.test(draftText) || /\{\{[^}]*\}\}/.test(draftText))) {
    draftText   = deterministicText;
    draftSource = 'ai_failed_fallback';
    if (aiAttempt) aiAttempt = { ...aiAttempt, validation_errors: (aiAttempt.validation_errors||[]).concat(['unresolved token in final draft_text']) };
  }

  const missingVariables = [];
  if (!firstName  && tmpl && !tmpl.suppressFirstName) missingVariables.push('firstName');
  if (!senderName) missingVariables.push('senderName');
  if (tmpl && tmpl.bookingLinkLine && !bookingLink) missingVariables.push('bookingLink');

  const draft = {
    template_id:           decision.reply_template_id || null,
    micro_intent:          microIntent,
    draft_policy:          draftPolicy,
    draft_source:          draftSource,
    draft_text:            draftText,
    draft_status:          decision.reply_draft_status || 'NOT_APPLICABLE',
    missing_variables:     missingVariables,
    human_review_required: decision.human_review_required === true,
    detected_intents: cls.detected_intents || [],
    ai_attempt: aiAttempt ? {
      provider:          AI_DRAFT_PROVIDER,
      model:             AI_DRAFT_MODEL,
      ok:                aiAttempt.ok,
      error:             aiAttempt.error   || null,
      reasoning_summary: aiAttempt.reasoning_summary || null,
      risk_flags:        aiAttempt.risk_flags         || [],
      validation_errors: aiAttempt.validation_errors  || [],
      raw_draft_text:    aiAttempt.draft_text          || null
    } : null,
    notes: draftPolicy === 'HUMAN_ONLY'
      ? 'Human-only category per policy-HMZ-1.2. No automated draft.'
      : (draftPolicy === 'NO_DRAFT' ? 'No draft applicable (OOO/bounce/noop).' : null)
  };

  results.push({ json: { ...input, draft } });
}

return results;

const items = $input.all();

const ALLOWED_CATEGORIES = [
  'POSITIVE_INTEREST', 'INFORMATION_REQUEST', 'BOOKING_REQUEST', 'TIMING_OBJECTION',
  'REFERRAL', 'NOT_INTERESTED', 'UNSUBSCRIBE', 'OUT_OF_OFFICE', 'BOUNCE_OR_DELIVERY_NOTICE',
  'WRONG_PERSON', 'PRICING_OR_COMMERCIAL_NEGOTIATION', 'LEGAL_PRIVACY_OR_COMPLAINT',
  'HOSTILE_OR_REPUTATIONAL_RISK', 'ATTACHMENT_REQUIRES_REVIEW', 'AMBIGUOUS', 'OTHER'
];

const REQUIRED_DECISION_FIELDS = [
  'category', 'confidence', 'confidence_overridden', 'stop_active_sequence',
  'durable_dnc_intent', 'address_suppression_intent', 'review_hold',
  'legal_review_required', 'privacy_review_required', 'reputational_review_required',
  'human_review_required', 'reply_permitted', 'reply_template_id', 'reply_draft_status',
  'external_action_status', 'follow_up_date', 'interest_stage', 'terminal_status', 'reason'
];

const BOOLEAN_DECISION_FIELDS = [
  'confidence_overridden', 'stop_active_sequence', 'durable_dnc_intent', 'review_hold',
  'legal_review_required', 'privacy_review_required', 'reputational_review_required',
  'human_review_required', 'reply_permitted'
];

const OPTIONAL_BOOLEAN_DECISION_FIELDS = [
  'pause_active_sequence', 'data_cleanup_required', 'referred_person_contact_permitted'
];

const ALLOWED_SUPPRESSION_INTENTS = ['NONE', 'REVIEW_HOLD', 'ORGANISATION_DNC', 'GLOBAL_BLOCKLIST'];
const ALLOWED_TERMINAL_STATUSES = ['REVIEW_HOLD', 'COMPLETED_NO_SEND', 'REJECTED'];
const ALLOWED_EXTERNAL_ACTION_STATUSES = ['NOT_PERFORMED', 'NOOP'];
const ALLOWED_DRAFT_STATUSES = [
  'DRAFT_PENDING_REVIEW', 'NOT_APPLICABLE', 'NO_DRAFT_HUMAN_ONLY', 'BLOCKED_PENDING_SUPPRESSION_VERIFICATION'
];
const ALLOWED_INTEREST_STATUS_UPDATES = ['NOT_INTERESTED'];
const ALLOWED_INTEREST_STAGES = ['DISCOVERY_ONLY', 'VALIDATION_SPRINT_INTEREST', 'ALPHA_INTEREST', 'UNKNOWN'];

const VALIDATION_LEARNING_TRISTATE_FIELDS = [
  'pain_confirmed', 'current_outbound_spend_confirmed', 'capacity_problem_confirmed',
  'proof_objection', 'pricing_interest', 'alpha_interest', 'decision_maker_confirmed',
  'discovery_call_booked', 'discovery_call_showed'
];

const PROHIBITED_CLAIM_PATTERNS = [
  { pattern: /guarantee/i, label: 'guarantee claim' },
  { pattern: /proven|proves|proof of/i, label: 'proven/proof claim' },
  { pattern: /case stud/i, label: 'case study claim' },
  { pattern: /testimonial/i, label: 'testimonial claim' },
  { pattern: /\$\s?\d/, label: 'price disclosure' },
  { pattern: /20\+/, label: '20-plus scale claim' },
  { pattern: /established|industry leader/i, label: 'maturity claim' }
];

function isTriState(value) {
  return value === true || value === false || value === 'unknown';
}

return items.map(item => {
  const rawItem = item.json || {};
  // HMZ_INPUT_UNWRAP_V2
  const input = rawItem.__hmz_intake_output || rawItem.case_input || rawItem;
  const decision = input.decision || {};
  const draft = input.draft || {};
  const nes = input.nes || {};
  const validationLearning = (input.classifier && input.classifier.validation_learning) || {};

  const errors = [];

  for (const field of REQUIRED_DECISION_FIELDS) {
    if (!Object.prototype.hasOwnProperty.call(decision, field)) {
      errors.push(`decision.${field} is missing`);
    }
  }

  if (decision.category !== null && !ALLOWED_CATEGORIES.includes(decision.category)) {
    errors.push(`decision.category "${decision.category}" is not an allowed category`);
  }

  if (typeof decision.confidence !== 'number' || decision.confidence < 0 || decision.confidence > 1) {
    errors.push(`decision.confidence "${decision.confidence}" is not a number between 0 and 1`);
  }

  for (const field of BOOLEAN_DECISION_FIELDS) {
    if (Object.prototype.hasOwnProperty.call(decision, field) && typeof decision[field] !== 'boolean') {
      errors.push(`decision.${field} must be true or false, got ${JSON.stringify(decision[field])}`);
    }
  }
  for (const field of OPTIONAL_BOOLEAN_DECISION_FIELDS) {
    if (Object.prototype.hasOwnProperty.call(decision, field) && typeof decision[field] !== 'boolean') {
      errors.push(`decision.${field} must be true or false, got ${JSON.stringify(decision[field])}`);
    }
  }

  for (const field of VALIDATION_LEARNING_TRISTATE_FIELDS) {
    if (Object.prototype.hasOwnProperty.call(validationLearning, field) && !isTriState(validationLearning[field])) {
      errors.push(`validation_learning.${field} must be true, false, or "unknown", got ${JSON.stringify(validationLearning[field])}`);
    }
  }

  if (!ALLOWED_SUPPRESSION_INTENTS.includes(decision.address_suppression_intent)) {
    errors.push(`decision.address_suppression_intent "${decision.address_suppression_intent}" is not an allowed suppression intent`);
  }

  if (Object.prototype.hasOwnProperty.call(decision, 'interest_status_update') &&
      !ALLOWED_INTEREST_STATUS_UPDATES.includes(decision.interest_status_update)) {
    errors.push(`decision.interest_status_update "${decision.interest_status_update}" is not an allowed value`);
  }

  if (!ALLOWED_INTEREST_STAGES.includes(decision.interest_stage)) {
    errors.push(`decision.interest_stage "${decision.interest_stage}" is not an allowed value`);
  }
  if (decision.interest_stage === 'ALPHA_INTEREST') {
    errors.push('decision.interest_stage is ALPHA_INTEREST; this must never be set automatically (policy-HMZ-1.2)');
  }

  if (!ALLOWED_EXTERNAL_ACTION_STATUSES.includes(decision.external_action_status)) {
    errors.push(`decision.external_action_status "${decision.external_action_status}" implies a real external action; only NOT_PERFORMED or NOOP are allowed in Phase 3`);
  }

  if (!ALLOWED_TERMINAL_STATUSES.includes(decision.terminal_status)) {
    errors.push(`decision.terminal_status "${decision.terminal_status}" is not an allowed terminal status`);
  }
  if (!ALLOWED_DRAFT_STATUSES.includes(decision.reply_draft_status)) {
    errors.push(`decision.reply_draft_status "${decision.reply_draft_status}" is not an allowed draft status`);
  }
  if (Object.prototype.hasOwnProperty.call(draft, 'draft_status') &&
      !ALLOWED_DRAFT_STATUSES.includes(draft.draft_status)) {
    errors.push(`draft.draft_status "${draft.draft_status}" is not an allowed draft status`);
  }

  if (typeof draft.draft_text === 'string') {
    for (const entry of PROHIBITED_CLAIM_PATTERNS) {
      if (entry.pattern.test(draft.draft_text)) {
        errors.push(`draft.draft_text appears to contain a ${entry.label}`);
      }
    }
  }

  if (nes.operating_mode === 'VALIDATION' && decision.reply_permitted === true && decision.human_review_required !== true) {
    errors.push('decision.reply_permitted is true but human_review_required is not true under OPERATING_MODE=VALIDATION');
  }

  const valid = errors.length === 0;
  let finalDecision = decision;

  if (!valid) {
    finalDecision = {
      ...decision,
      review_hold: true,
      human_review_required: true,
      reply_permitted: false,
      external_action_status: 'NOT_PERFORMED',
      terminal_status: 'REVIEW_HOLD',
      reason: `Output validation failed (${errors.length} issue(s)) - routed to REVIEW_HOLD. Original reason: ${decision.reason || 'none'}`
    };
  }

  return {
    json: {
      ...input,
      decision: finalDecision,
      validation: {
        valid,
        errors,
        checked_at: new Date().toISOString()
      },
      validation_learning: validationLearning
    }
  };
});

const items = $input.all();

// HMZ_INJECT_BEGIN:SUPPRESSION_ACTION_ENABLEMENT
const SUPPRESSION_ACTION_ENABLEMENT = {"source_campaign_stop_enabled":false,"interest_status_update_enabled":false,"subsequence_removal_enabled":false,"exact_email_blocklist_enabled":false};
// HMZ_INJECT_END:SUPPRESSION_ACTION_ENABLEMENT

const DNC_SCOPES = ['WORKSPACE_DNC', 'ORGANISATION_DNC', 'GLOBAL_BLOCKLIST'];

const INTEREST_VALUE_MAP = {
  INTERESTED: 1,
  MEETING_BOOKED: 2,
  MEETING_COMPLETED: 3,
  CLOSED: 4,
  OUT_OF_OFFICE: 0,
  NOT_INTERESTED: -1,
  WRONG_PERSON: -2,
  LOST: -3,
  DO_NOT_CONTACT: -1,
  UNSUBSCRIBE: -1,
};

function buildSafetyActionPlan(input) {
  const nes = input.nes || {};
  const decision = input.decision || {};
  const campaign = nes.campaign_context || {};
  const actions = [];

  if (decision.stop_active_sequence === true) {
    actions.push({
      action: 'SOURCE_CAMPAIGN_STOP',
      enabled: SUPPRESSION_ACTION_ENABLEMENT.source_campaign_stop_enabled,
      requires_canonical_lead_id: true,
      request_contract: {
        method: 'POST',
        url: 'https://api.instantly.ai/api/v2/leads/subsequence/remove',
        body: { id: null, campaign_id: campaign.campaign_id || null },
      },
    });

    const categoryKey = decision.category || '';
    const interestValue = Object.prototype.hasOwnProperty.call(INTEREST_VALUE_MAP, categoryKey)
      ? INTEREST_VALUE_MAP[categoryKey]
      : null;
    actions.push({
      action: 'UPDATE_INTEREST_STATUS',
      enabled: SUPPRESSION_ACTION_ENABLEMENT.interest_status_update_enabled,
      requires_canonical_lead_id: false,
      request_contract: {
        method: 'POST',
        url: 'https://api.instantly.ai/api/v2/leads/update-interest-status',
        body: { lead_email: nes.lead_email || null, interest_value: interestValue, campaign_id: campaign.campaign_id || null },
      },
    });
  }

  if (DNC_SCOPES.includes(decision.address_suppression_intent)) {
    actions.push({
      action: 'SUBSEQUENCE_REMOVAL',
      scope: decision.address_suppression_intent,
      enabled: SUPPRESSION_ACTION_ENABLEMENT.subsequence_removal_enabled,
      requires_canonical_lead_id: true,
      request_contract: {
        method: 'POST',
        url: 'https://api.instantly.ai/api/v2/leads/subsequence/remove',
        body: { id: null },
      },
    });
    actions.push({
      action: 'EXACT_EMAIL_BLOCKLIST',
      scope: decision.address_suppression_intent,
      enabled: SUPPRESSION_ACTION_ENABLEMENT.exact_email_blocklist_enabled,
      requires_canonical_lead_id: false,
      request_contract: {
        method: 'POST',
        url: 'https://api.instantly.ai/api/v2/block-lists-entries/bulk-create',
        body: { bl_values: [nes.lead_email || null] },
      },
    });
  }

  const requiresCanonicalLead = actions.some((a) => a.requires_canonical_lead_id && a.enabled);

  const plannedActions = actions.map((a) => ({
    ...a,
    executed: false,
    verification_status: a.enabled ? 'PLANNED_AWAITING_LIVE_GATE' : 'SUPPRESSION_ACTION_DISABLED_BY_CONFIG',
  }));

  return {
    schema_version: '1.1',
    required: plannedActions.length > 0,
    requires_canonical_lead: requiresCanonicalLead,
    actions: plannedActions,
    execution_order: 'BEFORE_REPLY_APPROVAL_GATE',
    note: 'Required suppression actions are planned and contract-defined here, independent of and prior to the prospect-reply human-approval gate (workflow 07) and the reply send gates (workflow 03). Each action is gated individually by its own flag in suppression_action_enablement and is executed/verified independently; real HTTP execution remains additionally gated by dry_run and live_credential_readiness.',
  };
}

return items.map(item => {
  const rawItem = item.json || {};
  // HMZ_INPUT_UNWRAP_V2
  const input = rawItem.__hmz_intake_output || rawItem.case_input || rawItem;
  return { json: { ...input, safety_action_plan: buildSafetyActionPlan(input) } };
});

